"""Subscriber: manages subscriptions and message delivery.

Uses _sub_lock to protect subscription table.
Coordinates with broker.py for routing.
"""

import threading
from typing import Callable, Dict, List


class Subscriber:
    """Manages per-topic subscriptions and delivers messages to callbacks."""

    def __init__(self):
        self._sub_lock = threading.Lock()
        self._subscriptions: Dict[str, List[Callable]] = {}
        self._delivered: int = 0
        self._broker = None  # set by set_broker()

    def set_broker(self, broker):
        self._broker = broker

    def subscribe(self, topic: str, callback: Callable) -> None:
        """Register a callback for a topic."""
        with self._sub_lock:
            if topic not in self._subscriptions:
                self._subscriptions[topic] = []
            if callback not in self._subscriptions[topic]:
                self._subscriptions[topic].append(callback)

    def unsubscribe(self, topic: str, callback: Callable) -> None:
        """Remove a callback and notify broker to update routing.

        BUG 1: Holds _sub_lock then calls broker.remove_subscriber()
        which acquires _broker_lock. Lock order: sub->broker.
        broker.route_message() does broker->sub. => ABBA deadlock.
        """
        with self._sub_lock:
            if topic in self._subscriptions:
                self._subscriptions[topic] = [
                    cb for cb in self._subscriptions[topic] if cb != callback
                ]
            if self._broker is not None:
                self._broker.remove_subscriber(topic, callback)  # BUG: calls out while holding _sub_lock

    def deliver(self, topic: str, message: str, callback: Callable) -> int:
        """Deliver a message to a single callback. Returns 1 on success."""
        with self._sub_lock:
            if topic in self._subscriptions and callback in self._subscriptions[topic]:
                try:
                    callback(message)
                    self._delivered += 1
                    return 1
                except Exception:
                    return 0
        return 0

    def get_stats(self) -> dict:
        with self._sub_lock:
            return {
                "total_subscriptions": sum(len(v) for v in self._subscriptions.values()),
                "topics": list(self._subscriptions.keys()),
                "delivered": self._delivered,
            }
